exercises.expected_solution:
// TradeExecutedEvent is the Avro-generated class.
// Builder pattern generated by avro-maven-plugin.

import org.springframework.kafka.core.KafkaTemplate;
import org.springframework.stereotype.Service;

@Service
public class TradeEventPublisher {
    private final KafkaTemplate<String, TradeExecutedEvent> kafkaTemplate;

    TradeEventPublisher(KafkaTemplate<String, TradeExecutedEvent> kt) {
        kafkaTemplate = kt;
    }

    public void publishTrade(String tradeId, String symbol, int qty,
                              double price, String type) {
        // Generated builder pattern:
        TradeExecutedEvent event = TradeExecutedEvent.newBuilder()
            .setTradeId(tradeId)
            .setSymbol(symbol)
            .setQty(qty)
            .setPrice(price)
            .setTotalValue(qty * price)
            .setTradeType(type)   // or TradeType.BUY if enum is generated
            .build();

        // KafkaAvroSerializer handles Avro → binary + schema registration:
        kafkaTemplate.send("trade-executed", symbol, event)
            .whenComplete((result, ex) -> {
                if (ex != null) System.err.println("Send failed: " + ex.getMessage());
            });
    }
}

