exercises.expected_solution:
// Version 2 TradeExecutedEvent.avsc:
// {
//   "type": "record",
//   "name": "TradeExecutedEvent",
//   "namespace": "com.codequest.events.avro",
//   "fields": [
//     {"name": "tradeId",    "type": "string"},
//     {"name": "symbol",     "type": "string"},
//     {"name": "qty",        "type": "int"},
//     {"name": "price",      "type": "double"},
//     {"name": "tradeType",  "type": "string"},
//     {"name": "sector",     "type": ["null", "string"], "default": null},
//     {"name": "region",     "type": ["null", "string"], "default": null}
//   ]
// }

// Why backward compatible:
// - Old consumers reading v2 events: sector/region fields may be present
//   but old consumers ignore unknown fields (Avro reader schema controls this)
// - New consumers reading v1 events: sector/region absent → use default null
// - Schema Registry: COMPATIBLE (added with defaults)

// Generated Java for new fields:
// CharSequence getSector() → returns null if not set (union type)
// CharSequence getRegion() → returns null if not set

// Usage in producer (v2 events):
// TradeExecutedEvent.newBuilder()
//   .setTradeId("TRD-001")
//   ...existing fields...
//   .setSector("Technology")  // new field
//   .setRegion("India")       // new field
//   .build();

public class SchemaEvolutionExample {
    public static void main(String[] args) {
        System.out.println("Version 2 adds sector and region with null defaults");
        System.out.println("Backward compatible: old consumers see null for new fields");
        System.out.println("Schema Registry: is_compatible=true");
    }
}

