import org.springframework.kafka.core.KafkaTemplate;
import org.springframework.kafka.annotation.KafkaListener;
import org.springframework.stereotype.Service;

// Producer service:
@Service
public class PaymentEventPublisher {
    private final KafkaTemplate<String, PaymentEvent> kafkaTemplate;
    PaymentEventPublisher(KafkaTemplate<String, PaymentEvent> kt) { kafkaTemplate = kt; }

    public void publishPayment(String paymentId, String userId, double amount, String status) {
        PaymentEvent event = PaymentEvent.newBuilder()
            .setPaymentId(paymentId)
            .setUserId(userId)
            .setAmount(amount)
            .setStatus(status)
            .build();
        kafkaTemplate.send("payment-events", userId, event);
    }
}

// Consumer service:
@Service
public class PaymentAnalyticsConsumer {
    @KafkaListener(topics = "payment-events", groupId = "analytics-avro")
    public void handlePayment(PaymentEvent event) {
        System.out.printf("Payment: userId=%s amount=₹%.2f status=%s%n",
            event.getUserId(), event.getAmount(), event.getStatus());
    }
}

