exercises.expected_solution:
// SAFE MIGRATION: Rename 'price' → 'unitPrice' in 2 steps

// VERSION 2 .avsc (backward compatible — add new field, keep old):
// {
//   "type": "record", "name": "TradeEvent", "namespace": "com.codequest",
//   "fields": [
//     {"name": "tradeId",   "type": "string"},
//     {"name": "price",     "type": "double"},           ← KEEP existing
//     {"name": "unitPrice", "type": "double", "default": 0.0}  ← ADD new with default
//   ]
// }
// Schema Registry: COMPATIBLE ✓ (added with default)
// Deploy: Producers set BOTH price AND unitPrice. Consumers can read either.

// VERSION 3 .avsc (after ALL consumers updated to use unitPrice):
// {
//   "type": "record", "name": "TradeEvent", "namespace": "com.codequest",
//   "fields": [
//     {"name": "tradeId",   "type": "string"},
//     {"name": "unitPrice", "type": "double"}             ← REMOVE old 'price'
//   ]
// }
// Schema Registry: COMPATIBLE (forward compat — old data had 'price' with default → ignored)
// This works IF 'price' had a default. If not: still breaking!

// WHY 2 DEPLOYS:
// 1 deploy: old consumers still expect 'price'. Adding 'unitPrice' with default is safe.
//           New consumers can start using 'unitPrice'.
// 2nd deploy (after all consumers migrated): remove 'price'.
//           Now all data uses 'unitPrice'. Migration complete.
// 1-deploy rename: old consumers break immediately → production incident

public class MigrationStrategy {
    public static void main(String[] args) {
        System.out.println("Step 1: Add unitPrice with default, keep price");
        System.out.println("Step 2: After all consumers updated, remove price");
    }
}

